WITH pending AS (
  SELECT
    d.*,
    COALESCE(
      d.context_used->>'repo_full_name', d.context_used->>'repo',
      d.evidence->>'repo_full_name', d.evidence->>'repo',
      d.decision->>'repo_full_name', d.decision->>'repo'
    ) AS decision_repo,
    COALESCE(
      d.context_used->>'pull_request_number', d.context_used->>'pr_number',
      d.evidence->>'pull_request_number', d.evidence->>'pr_number',
      d.decision->>'pull_request_number', d.decision->>'pr_number'
    ) AS decision_pr_number
  FROM ai_decisions d
  WHERE d.status = 'pending_approval'
), resolved_by_github AS (
  SELECT p.decision_id, gh.event_type, gh.occurred_at
  FROM pending p
  JOIN LATERAL (
    SELECT e.event_type, e.occurred_at, e.received_at
    FROM events_inbox e
    WHERE e.source = 'github'
      AND (
        e.correlation_id = p.correlation_id
        OR (
          p.decision_repo IS NOT NULL
          AND p.decision_pr_number ~ '^[0-9]+$'
          AND e.repo = p.decision_repo
          AND e.pull_request_number = p.decision_pr_number::integer
        )
      )
      AND (
        e.event_type IN ('github_pr_merged', 'github_pr_closed')
        OR (
          e.event_type ILIKE '%review%'
          AND lower(COALESCE(e.normalized->>'review_state', e.payload#>>'{body,review,state}', '')) = 'approved'
        )
      )
    ORDER BY e.occurred_at DESC NULLS LAST, e.received_at DESC NULLS LAST
    LIMIT 1
  ) gh ON TRUE
)
UPDATE ai_decisions d
SET
  status = CASE WHEN r.event_type = 'github_pr_closed' THEN 'externally_closed' ELSE 'externally_approved' END,
  approved_by = COALESCE(d.approved_by, 'github'),
  approved_at = COALESCE(d.approved_at, r.occurred_at, NOW()),
  action_taken = COALESCE(d.action_taken, 'github:' || r.event_type)
FROM resolved_by_github r
WHERE d.decision_id = r.decision_id;

WITH stats AS (
  SELECT json_build_object(
    'approvals_pending', (SELECT COUNT(*) FROM ai_decisions WHERE status = 'pending_approval'),
    'approvals_high', (SELECT COUNT(*) FROM ai_decisions WHERE status = 'pending_approval' AND risk_level IN ('high', 'critical')),
    'approvals_stale', (SELECT COUNT(*) FROM ai_decisions WHERE status = 'pending_approval' AND created_at < NOW() - INTERVAL '24 hours'),
    'approvals_critical', (SELECT COUNT(*) FROM ai_decisions WHERE status = 'pending_approval' AND risk_level = 'critical'),
    'pm_tasks_from_approvals', (SELECT COUNT(*) FROM pm_tareas WHERE creado_por = 'approval_hub'),
    'outbox_pending', (SELECT COUNT(*) FROM events_outbox WHERE status IN ('pending', 'sending')),
    'outbox_dead', (SELECT COUNT(*) FROM events_outbox WHERE status = 'dead'),
    'inbox_backlog', (SELECT COUNT(*) FROM events_inbox WHERE processing_status IN ('ingested', 'pending', 'processing')),
    'events_24h', (SELECT COUNT(*) FROM events_inbox WHERE received_at > NOW() - INTERVAL '24 hours'),
    'github_events_24h', (SELECT COUNT(*) FROM events_inbox WHERE source = 'github' AND received_at > NOW() - INTERVAL '24 hours'),
    'trello_events_24h', (SELECT COUNT(*) FROM events_inbox WHERE source = 'trello' AND received_at > NOW() - INTERVAL '24 hours'),
    'tasks_open', (SELECT COUNT(*) FROM estado_tareas WHERE completada = false),
    'tasks_overdue', (SELECT COUNT(*) FROM estado_tareas WHERE completada = false AND fecha_vencimiento < NOW()),
    'tasks_due_48h', (SELECT COUNT(*) FROM estado_tareas WHERE completada = false AND fecha_vencimiento BETWEEN NOW() AND NOW() + INTERVAL '48 hours'),
    'phases_active', (SELECT COUNT(*) FROM project_phases WHERE status = 'active'),
    'docs_pending_summary', (SELECT COUNT(*) FROM card_attachments WHERE summary_extracted IS NULL),
    'reports_7d', (SELECT COUNT(*) FROM reportes_generados WHERE fecha > NOW() - INTERVAL '7 days'),
    'ai_decisions_7d', (SELECT COUNT(*) FROM ai_decisions WHERE created_at > NOW() - INTERVAL '7 days'),
    'audit_errors_24h', (SELECT COUNT(*) FROM workflow_runs_audit WHERE status = 'error' AND started_at > NOW() - INTERVAL '24 hours'),
    'last_event_at', (SELECT MAX(received_at) FROM events_inbox),
    'last_report_at', (SELECT MAX(fecha) FROM reportes_generados)
  ) AS stats
), approval_rows AS (
  SELECT COALESCE(json_agg(t), '[]'::json) AS approvals
  FROM (
    SELECT
      d.decision_id, d.correlation_id, d.agent_role, d.decision_type, d.input_summary,
      d.recommendation, d.risk_level, d.confidence, d.created_at, d.status,
      d.context_used, d.evidence, d.decision, d.pm_impact, d.pm_next_action,
      d.pm_owner, d.pm_deadline, d.pm_risk_reason, d.approval_note, d.rejected_reason, d.approval_metadata,
      ROUND((EXTRACT(EPOCH FROM (NOW() - d.created_at))/3600)::numeric, 1) AS age_hours,
      gh.repo AS github_repo, gh.pull_request_number AS github_pr_number,
      gh.commit_sha AS github_commit_sha, gh.event_type AS github_event_type,
      gh.occurred_at AS github_event_at, gh.actor AS github_actor, gh.pr_url AS github_pr_url
    FROM ai_decisions d
    LEFT JOIN LATERAL (
      SELECT
        e.repo, e.pull_request_number, e.commit_sha, e.event_type, e.occurred_at, e.received_at, e.actor,
        COALESCE(
          e.normalized->>'url',
          e.payload#>>'{body,pull_request,html_url}',
          CASE WHEN e.repo IS NOT NULL AND e.pull_request_number IS NOT NULL THEN 'https://github.com/' || e.repo || '/pull/' || e.pull_request_number END
        ) AS pr_url
      FROM events_inbox e
      WHERE e.source = 'github'
        AND (
          e.correlation_id = d.correlation_id
          OR (
            e.repo = COALESCE(d.context_used->>'repo_full_name', d.context_used->>'repo', d.evidence->>'repo_full_name', d.evidence->>'repo', d.decision->>'repo_full_name', d.decision->>'repo')
            AND e.pull_request_number::text = COALESCE(d.context_used->>'pull_request_number', d.context_used->>'pr_number', d.evidence->>'pull_request_number', d.evidence->>'pr_number', d.decision->>'pull_request_number', d.decision->>'pr_number')
          )
        )
      ORDER BY e.occurred_at DESC NULLS LAST, e.received_at DESC NULLS LAST
      LIMIT 1
    ) gh ON TRUE
    WHERE d.status = 'pending_approval'
    ORDER BY
      CASE d.risk_level WHEN 'critical' THEN 0 WHEN 'high' THEN 1 WHEN 'medium' THEN 2 ELSE 3 END,
      d.created_at ASC
    LIMIT 50
  ) t
), recent_events AS (
  SELECT COALESCE(json_agg(t), '[]'::json) AS recent_events
  FROM (
    SELECT event_id, source, event_type, actor, repo, trello_card_id, pull_request_number, commit_sha,
           occurred_at, received_at, processing_status,
           COALESCE(normalized->>'url', normalized->>'card_url', payload#>>'{body,pull_request,html_url}') AS url
    FROM events_inbox
    ORDER BY received_at DESC
    LIMIT 18
  ) t
), recent_decisions AS (
  SELECT COALESCE(json_agg(t), '[]'::json) AS recent_decisions
  FROM (
    SELECT decision_id, agent_role, decision_type, input_summary, recommendation, risk_level, status,
           created_at, approved_at, approved_by, action_taken
    FROM ai_decisions
    WHERE status <> 'pending_approval'
    ORDER BY COALESCE(approved_at, created_at) DESC
    LIMIT 12
  ) t
), reliability AS (
  SELECT
    COALESCE((SELECT json_agg(t) FROM (SELECT outbox_id, event_id, target, action, retry_count, scheduled_at, last_error FROM events_outbox WHERE status = 'dead' ORDER BY scheduled_at DESC LIMIT 6) t), '[]'::json) AS dead_outbox,
    COALESCE((SELECT json_agg(t) FROM (SELECT event_id, source, event_type, retry_count, last_error, received_at FROM events_inbox WHERE processing_status IN ('error', 'failed') ORDER BY received_at DESC LIMIT 6) t), '[]'::json) AS failed_events
), work_items AS (
  SELECT
    COALESCE((SELECT json_agg(t) FROM (SELECT card_id, card_nombre, lista_nombre, miembro_nombre, fecha_vencimiento FROM estado_tareas WHERE completada = false AND fecha_vencimiento < NOW() ORDER BY fecha_vencimiento ASC LIMIT 8) t), '[]'::json) AS overdue_tasks,
    COALESCE((SELECT json_agg(t) FROM (SELECT attachment_id, card_id, card_name, filename, added_at, url FROM card_attachments WHERE summary_extracted IS NULL ORDER BY added_at DESC LIMIT 8) t), '[]'::json) AS docs_pending,
    COALESCE((SELECT json_agg(t) FROM (SELECT phase_id, name, status, responsible, start_date, end_date FROM project_phases WHERE status = 'active' ORDER BY end_date ASC NULLS LAST LIMIT 8) t), '[]'::json) AS active_phases
)
SELECT
  approval_rows.approvals,
  stats.stats,
  recent_events.recent_events,
  recent_decisions.recent_decisions,
  reliability.dead_outbox,
  reliability.failed_events,
  work_items.overdue_tasks,
  work_items.docs_pending,
  work_items.active_phases
FROM approval_rows, stats, recent_events, recent_decisions, reliability, work_items;

