const payload = $json || {};
const parseArray = (value) => {
  if (!value) return [];
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') { try { const parsed = JSON.parse(value); return Array.isArray(parsed) ? parsed : []; } catch (_) { return []; } }
  return [];
};
const parseObj = (value) => {
  if (!value) return {};
  if (typeof value === 'object' && !Array.isArray(value)) return value;
  if (typeof value === 'string') { try { const parsed = JSON.parse(value); return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {}; } catch (_) { return {}; } }
  return {};
};

const rows = parseArray(payload.approvals);
const stats = parseObj(payload.stats);
const recentEvents = parseArray(payload.recent_events);
const recentDecisions = parseArray(payload.recent_decisions);
const deadOutbox = parseArray(payload.dead_outbox);
const failedEvents = parseArray(payload.failed_events);
const overdueTasks = parseArray(payload.overdue_tasks);
const docsPending = parseArray(payload.docs_pending);
const activePhases = parseArray(payload.active_phases);
const approvalToken = String($('Webhook - Dashboard').first().json.query?.token || '');

const riskColor = { low: '#1f9d55', medium: '#c2872f', high: '#c85f3d', critical: '#b42318' };
const riskLabel = { low: 'Bajo', medium: 'Medio', high: 'Alto', critical: 'Critico' };
const eventLabel = {
  github_pr_opened: 'PR abierto', github_pr_ready: 'PR listo', github_pr_updated: 'PR actualizado',
  github_pr_merged: 'PR mergeado', github_pr_closed: 'PR cerrado', github_pr_review_approved: 'PR aprobado',
  trello_card_move: 'Trello movimiento', trello_comment: 'Trello comentario', trello_card_created: 'Trello creada', trello_due_changed: 'Fecha Trello'
};

const esc = (value) => String(value ?? '')
  .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const first = (...values) => values.find((value) => value !== undefined && value !== null && String(value).trim() !== '');
const normalizePr = (value) => { const raw = first(value); if (!raw) return ''; const m = String(raw).match(/\d+/); return m ? m[0] : ''; };
const shortSha = (value) => first(value) ? String(value).slice(0, 8) : '';
const formatDate = (value) => value ? new Date(value).toLocaleString('es-EC', { timeZone: 'America/Guayaquil', dateStyle: 'medium', timeStyle: 'short' }) : '-';
const formatDateShort = (value) => value ? new Date(value).toLocaleDateString('es-EC', { timeZone: 'America/Guayaquil', month: 'short', day: 'numeric' }) : '-';
const n = (value) => Number(value || 0);

const unwrapEventDetails = (obj) => {
  const details = obj?.event_details ?? obj?.eventDetails ?? obj?.details;
  return typeof details === 'string' ? parseObj(details) : parseObj(details);
};
const enrich = (r) => {
  const context = parseObj(r.context_used);
  const evidence = parseObj(r.evidence);
  const decision = parseObj(r.decision);
  const eventDetails = unwrapEventDetails(context);
  const decisionRaw = parseObj(decision.raw);
  const repo = first(r.github_repo, context.repo_full_name, context.repo, evidence.repo_full_name, evidence.repo, decision.repo_full_name, decision.repo, eventDetails.repo_full_name, eventDetails.repo, decisionRaw.repo_full_name, decisionRaw.repo);
  const prNumber = normalizePr(first(r.github_pr_number, context.pull_request_number, context.pr_number, evidence.pull_request_number, evidence.pr_number, decision.pull_request_number, decision.pr_number, eventDetails.pull_request_number, eventDetails.pr_number, decisionRaw.pull_request_number, decisionRaw.pr_number));
  const commit = shortSha(first(r.github_commit_sha, context.commit_sha, context.sha, evidence.commit_sha, evidence.sha, decision.commit_sha, decision.sha, eventDetails.commit_sha, eventDetails.sha, decisionRaw.commit_sha, decisionRaw.sha));
