      const risk = document.getElementById('risk')?.value || '';
      document.querySelectorAll('.approval-card').forEach((card) => {
        const hit = (!q || card.dataset.search.includes(q)) && (!risk || card.dataset.risk === risk);
        card.style.display = hit ? 'grid' : 'none';
      });
    }
    async function decide(id, action, suggestedTask, createTask = false) {
      if (!approvalToken) return showToast('Falta token de aprobacion en la URL.');
      const note = window.prompt(action === 'approved' ? 'Nota de aprobacion o condicion de seguimiento:' : 'Motivo del rechazo:', '');
      if (note === null) return;
      let taskTitle = suggestedTask || '';
      if (createTask) {
        const customTitle = window.prompt('Titulo de la tarea de seguimiento:', taskTitle);
        if (customTitle === null) return;
        taskTitle = customTitle || taskTitle;
      }
      const card = document.querySelector('[data-id="' + id + '"]');
      const buttons = card ? card.querySelectorAll('button') : [];
      buttons.forEach((btn) => { btn.disabled = true; btn.style.opacity = '0.7'; });
      if (card) card.style.opacity = '0.72';
      try {
        const res = await fetch('/webhook/pm-approve', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', ...(approvalToken ? { 'x-pm-token': approvalToken } : {}) },
          body: JSON.stringify({ decision_id: id, action, approved_by: 'tech-lead', token: approvalToken, note, create_task: createTask, task_title: taskTitle })
        });
        const data = await res.json().catch(() => ({}));
        if (!res.ok) throw new Error(data.error || 'No se pudo procesar la decision');
        showToast(action === 'approved' ? 'Decision aprobada correctamente' : 'Decision rechazada correctamente');
        setTimeout(() => window.location.reload(), 450);
      } catch (e) {
        showToast(e.message || 'Error al procesar. Intenta de nuevo.');
        buttons.forEach((btn) => { btn.disabled = false; btn.style.opacity = '1'; });
        if (card) card.style.opacity = '1';
      }
    }
    function showToast(msg) { const t = document.getElementById('toast'); t.textContent = msg; t.style.display = 'block'; setTimeout(() => { t.style.display = 'none'; }, 3300); }
  </script>
</body>
</html>`;

return [{ json: { html } }];

