WITH updated AS (
  UPDATE ai_decisions
  SET
    status = $1,
    approved_by = $2,
    approved_at = NOW(),
    action_taken = 'dashboard:' || $1,
    approval_note = CASE WHEN $1 = 'approved' THEN NULLIF($4, '') ELSE approval_note END,
    rejected_reason = CASE WHEN $1 = 'rejected' THEN NULLIF($4, '') ELSE rejected_reason END,
    approval_metadata = jsonb_build_object('create_task', $5::boolean, 'task_title', $6, 'source', 'approval_hub')
  WHERE decision_id = $3::uuid
  RETURNING decision_id, agent_role, decision_type, input_summary, recommendation, risk_level, context_used, evidence, decision, approval_note, rejected_reason
), inserted_task AS (
  INSERT INTO pm_tareas (titulo, descripcion, responsable, prioridad, estado, fecha_limite, canal_origen, creado_por)
  SELECT
    COALESCE(NULLIF($6, ''), 'Seguimiento aprobacion ' || decision_id::text),
    COALESCE(NULLIF(recommendation, ''), input_summary, 'Tarea creada desde Approval Hub'),
    $2,
    CASE risk_level WHEN 'critical' THEN 'critica' WHEN 'high' THEN 'alta' WHEN 'medium' THEN 'media' ELSE 'baja' END,
    'pendiente',
    CURRENT_DATE + INTERVAL '1 day',
    'approval_hub',
    'approval_hub'
  FROM updated
  WHERE $1 = 'approved' AND $5::boolean = true
  RETURNING id
)
SELECT updated.*, (SELECT id FROM inserted_task LIMIT 1) AS created_task_id
FROM updated;

