const d = $json;
const actionBody = $('Webhook - Approve Action').item.json;
const action = actionBody.action;
const verb = action === 'approved' ? 'aprobada' : 'rechazada';

const parseMaybeJson = (value) => {
  if (!value) return {};
  if (typeof value === 'object') return value;
  try { return JSON.parse(value); } catch (_) { return {}; }
};
const first = (...values) => values.find((value) => value !== undefined && value !== null && String(value).trim() !== '');

const ctx = parseMaybeJson(d.context_used);
const ev = parseMaybeJson(d.evidence);
const dec = parseMaybeJson(d.decision);
const repo = first(ctx.repo_full_name, ctx.repo, ev.repo_full_name, ev.repo, dec.repo_full_name, dec.repo);
const prNumber = first(ctx.pull_request_number, ctx.pr_number, ev.pull_request_number, ev.pr_number, dec.pull_request_number, dec.pr_number);
const prUrl = first(ctx.pr_url, ctx.pull_request_url, ev.pr_url, ev.pull_request_url, dec.pr_url, dec.pull_request_url, repo && prNumber ? `https://github.com/${repo}/pull/${prNumber}` : '');

const lines = [
  `**Decision ${verb}** por el Tech Lead`,
  '',
  `**Agente:** ${d.agent_role || '-'}`,
  `**Tipo:** ${d.decision_type || '-'}`,
  `**Recomendacion:** ${d.recommendation || '-'}`,
  prUrl ? `**PR:** ${prUrl}` : null,
  actionBody.note ? `**Nota:** ${actionBody.note}` : null,
  d.created_task_id ? `**Tarea creada:** #${d.created_task_id}` : null,
  '',
  `ID: \`${d.decision_id}\``
].filter((line) => line !== null);

return [{ json: { content: lines.join('\n'), channel_id: $env.DISCORD_CHANNEL_REPORTES || $env.DISCORD_CHANNEL_ADMIN || '', event_id: 'approval:' + d.decision_id, idempotency_key: 'approval:' + d.decision_id + ':' + action } }];
